const crypto = require('crypto'); // Import the Crypto module from node's standard library 
// This is used for hashing password, it provides a way to hash data using one of several algorithms and produce an output that can be safely stored in your database.  
function generateHash(password) {   
return crypto.createHmac('sha256', 'secret') // Hashing algorithm here (md4 is default), secret key 
        .update(password, 'utf-8')     // Update the password with utf encoding for multi language support  
	.digest('hex');      // Create a hash and return it in hexadecimal format.   
}